import{_ as e,o as a,c as p,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"神经漫游者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/3.心智类/神经漫游者.md","filePath":"4.资源分区/2.改造与功法/改造/3.心智类/神经漫游者.md"}'),d={name:"4.资源分区/2.改造与功法/改造/3.心智类/神经漫游者.md"};function n(o,b,_,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"神经漫游者",tabindex:"-1"},[t("神经漫游者 "),r("a",{class:"header-anchor",href:"#神经漫游者","aria-label":'Permalink to "神经漫游者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="神经漫游者-1" tabindex="-1">神经漫游者 <a class="header-anchor" href="#神经漫游者-1" aria-label="Permalink to &quot;神经漫游者&quot;">​</a></h1><p>神经漫游者<br> 改造<br> 科技本质<br> 价格：D+600<br> 特性：【思维终端】【深度加密】【数据隧道】<br> 购买该改造后解锁后续技能树<br> 【USB接口】<br> 购买该改造后，轮回者的思维将可以随时接入网络世界，此时轮回者可以无需网络设备，紧紧依靠意识就能过链接互联网并且上网查询资料<br> 与此同时，轮回者还能获得一个特殊的U盘，该U盘链接大脑意识，其接口会自动适应电子设备接口型号。当轮回者想要入侵一个设备时，可以通过U盘接入设备进行入侵，效果等同于D级网络效果</p><p>【深度加密】<br> 你获得新专业-信息安全（智力+器用）<br> 对自身网络安全的加密，让神经漫游者想要悄无声息的入侵敌人防火墙，或者想要不被他人查询自身位置信息时起到信息保护的作用，对于自身数据的加密让神经漫游者可以在网络中可以更好的隐藏自身，你可以通过信息安全来对抗敌人的信息入侵，并且你视为拥有在网络世界生效的科技本质的无支线反侦查</p><p>【量子隧道】<br> 你获得新专业-意识同步（器械技能下属）<br> 神经漫游者通过意识网络向他人设备传输的信息将自动被量子加密，信息在传输过程中不会留下任何痕迹，他人通过设备受到信息后，可以直接在设备上进行文字输入，输入的文字将自动被神经漫游者接收。这视为一种D级的信息共享</p><p>量子驭者<br> 改造<br> 科技本质<br> C+1200<br> 特性：【身体改造】【思维终端】【深度加密-错误信号】【量子隧道】<br> 【身体改造】：<br> 为了更加适应高强度的网络使用需求，你哪怕长时间不休息也能精神满满的继续上网“冲浪”，并且高强度的冲浪让你无论在什么环境都能小歇片刻<br> 现在你无需休息并且获得自适应短休的能力</p><p>【思维终端】：<br> 你免疫B级信息来源的负面效果<br> 神经漫游者入侵网络系统不在局限于USB直连，现在神经漫游者可以通过信号网络来入侵一片区域的网络防火墙，局域网，机密设备等，这将替换D级【USB接口】特性，视为C级网络效果</p><p>【深度加密-错误信号】<br> 对自身网络安全的再度加密，当神经漫游者数据被其他人入侵时，加密的信息将增加他人查询的难度，并有概率被你放出的错误情报误导<br> 你可以提前设立错误情报，当你信息被入侵时，如果你通过信息安全对抗成功，那么你可以获得一次反向入侵对方的机会，并且可以选择是否让敌人获得你提前编织的错误情报<br> 这视为在网络世界中拥有科技本质的D级反侦查</p><p>【量子隧道】<br> 对于量子信息传输的理解与掌握，神经漫游者可以通过入侵他人的，可接入网络/局域网的设备，使对方的设备成为信息传输的中转站，通过信号中转站开辟特殊的量子隧道，可以使指定的人脑内接收到你想要传达的信息，对方也可以通过这条隧道将思维，想法传输回你的脑内<br> 这一信号交流的方式不会在设备上留下任何痕迹，效果等效于C级的信息共享，且每次只能链接一个人的思维</p><p>电子幽灵<br> 改造<br> 科技本质<br> B+2400<br> 特性：【电子幽灵】【思维终端】<br> 【电子幽灵】<br> 该特性将替换【身体改造】特性<br> 为了追求更高效的信息传输，你将舍弃原本的肉体，机械飞升，拥抱新的生命形式，成为某种意义上的永生者，神经漫游者将意识上传至网络，舍弃羸弱的躯体，化作网络中的一个电子幽灵<br> 神经漫游者可以通过量子的形式出现在现世，因此，传统意义上的物理伤害将不会对你照成影响，如同【虚体】般，成为真正意义上的电子幽灵，这也意味着你的生命值转变为1.5倍的结构值<br> 【思维终端】<br> 网络效果从C提升至B级，可入侵范围不在局限于一个片区，而是扩展至整片互联网，当自身接入成功入侵的互联网时，可以在智力相关检定上获得2dp器械加值<br> 在进行信息安全专业相关检定时，检定获得【9加骰】</p><p>机械之魂<br> 科技本质<br> A+4800<br> 特性：【信息侵蚀】【思维升华】【数据下载】<br> 【思维升华】<br> 你的思维算力已经超越任何超级计算机，哪怕面对未知科技，你也能在短时间内入侵并解析其原理，在网络世界，一切防火墙在你面前都形同虚设，你将闲庭信步的随意查看他人的隐私与机密信息。<br> 你的【量子隧道】与【思维终端】特性得到升级，网络特性与信息共享特性提升至A级。<br> 在进行意识同步专业相关检定时，检定获得【9加骰】</p><p>【信息侵蚀】<br> 网络中野蛮成长，在接收大量数据后，你现在已经具备大规模影响网络的能力；散播网络病毒，被病毒感染的设备将成为新的病原体，并通过网络感染更多的设备<br> 被感染的设备其存储的信息将被神经漫游者读取，备份。所有被感染的机体都将成为神经漫游者处理信息的服务器，为自身信息的处理提供大量的算力<br> 在战斗中，神经漫游者可以紧急调用被感染设备的算力，用以临时提升运算能力<br> 在战斗中，一个自由动作启动，你将调用其他设备的运算能力来强化思维运算，高频的运算下，你的行动将变得更为迅捷，高效<br> 在战斗轮中，你每轮都可以获得用于转化标准动作或进行该改造下属技艺的4AP。</p><p>【数据下载】<br> 你的思维与网络紧密相连，进入副本后，只要该世界还存在网络，电子设备等科技侧物品（含轮回者自己带的电子设备），只要被你入侵过，其都将残留你的部分思维信息，无论现实世界发生什么，你的思维都不会停止运行，当神经漫游者死亡时，如果副本世界内还存在残留你思维的电子设备，那么你不会真正意义上的死亡，而是在其上不断的修补自身数据，等待一周后，数据修补完全，你将再次重现于世界，这是一个A级信息来源的复活能力。<br> 当你死亡时，你需要立即进行一次信息安全检定（智力+器用+信息安全），以该次检定出目为DC，所有试图找寻你的意识数据备份的行为都需要以网络能力或电脑操控检定（或各类相关网络搜索检定）对该dc进行对抗，你的意识备份将会拥有等同于你意志池上限的特殊结构值，平均分散在你入侵过的至多5个设备中，每当搜寻者成功通过信息安全DC，你的所有意识备份都将承受超出DC数额的检定成功数等量的不可避免的严重伤害，并暴露出其中一个备份设备的具体位置；当所有备份被彻底破坏之后，你的复活将会失败，视为彻底死亡。</p><p>下属物品：</p><p>多功能组装台<br> 价格：D+500<br> 类别：奇物<br> 科技本质<br> 概述：外观酷似一个手提箱，其内部采取特殊空间压缩技术，如果采用正常方式打开，只能看到手提箱里面的生活物品，但通过特殊机关解锁后，手提箱将展开变为一个多功能工作台，其内附赠各种各样的无人机零件<br> 【折叠空间】【维修装置】<br> 【折叠空间】：你可以将无人机，或者杂物放入其中，不通过特殊手段打开是无法探查到其内藏匿的各种道具，这视为D级空间效果，最大存放不能超过10立方的物品，取出物品是一个迅捷动作<br> 当无人机损坏，或者报废时，你可以在长休，利用其内零件将其重新制造出来，但是其复活还是要遵从随从复活机制，每天只能复活一次，只有第二天才能复活<br> 【维修装置】：多功能组装台内含有零部件，依靠配件组装，对于机械造物的理解让你在内部空间搭建特殊的维修装置，放置在其内的机械造物将会自动修复破的外表<br> 每经历一个副本，多功能组装台将拥有1点快速维修（12医疗池），可以用于恢复其内的机械造物<br> 该效果最多成长3次，并且仅限战斗外恢复</p><p>下属技艺：</p><p>算力<br> 能量池<br> D+500<br> 能量池：算力<br> 关键属性：智力+操控<br> 主神空间从灭亡文明的残骸中抽离“思维余烬”，压缩为可量化资源，简称为算力<br> 恢复方式：<br> 1、在短休息时链接数据世界，恢复等同智力属性点的算力。<br> 2、在长休息后，恢复所有算力。<br> 能量池每日恢复不能超过能量池上限的3倍<br> 算力基础用法：使用含智力属性或器械技能的检定时，消耗一点算力可以增加1dp的能量加值，每次检定技能适用一次<br> 每轮一次，当你消耗算力时，可以至多减少等同于沉着传奇属性*1的算力消耗（最低降低至1）</p><p>支付C+1000强化能量池<br> 能量池上限会根据最高内在等级增加上限（D5、C10、B15、A20、S25）<br> 获得新的能量池恢复方式<br> 每小时进行一次能量关键属性的检定，恢复成功数点算力。<br> 只要该能量池不为空，你在承受伤害时就可以加速演算，使得自身的伤势快速修复，这视为具有【快速维修1】（12点维修点数）<br> 算力基础用法：使用含智力属性或器械技能的鉴定时，消耗一点算力可以增加3dp的能量加值，每次鉴定只能用一次</p><p>当面开盒小子！<br> 技艺<br> 科技本质<br> 价格：D+500<br> 特性：【当面开盒！】【盒威慑】<br> 【当面开盒！】<br> 日常中，轮回者可以通过名字查询对方ip地址，或入侵对方在网络，查询对方上网痕迹<br> 战斗中，你可以消耗一个花招动作，对眼前的敌人进行一次人脸识别，然后对其狠狠的开盒！<br> 你进行一次智力+器用+信息安全检定，对方以潜藏检定进行对抗，如果你对抗成功，则可以通过网络检索对方在互联网上留下的信息，你可以通过该方法了解对方的在互联网留下的能力效果（注意：这需要对方确实在互联网上留下了相关信息，若这一世界不具有互联网或是对方并不上网，则这一效果无法生效）。例如：弱点、还有对方的护甲防御类型和效果、武器的效果与破防，这视为D级信息来源的解析效果。<br> 你可以通过开盒额外获得对方的各种黑历史与丑事，这些都由st提供<br> 【盒威慑】<br> 当你成功入开盒敌人，你可以用一个花自由动作，爆出对方身份信息，丑事，或黑历史，对方听到将不可避免的感到震惊，或者惊恐，并在接下来一回合内面攻击出现走神，分心等行为。<br> 目标需要使用意志豁免对抗你的电脑操作，如果意志豁免对抗失败，则进入措手不及状态<br> 这视为持续一回合的D级措手不及效果，针对每个目标，每轮只能使用一次，一次只能对一个目标生效</p><p>信息过载<br> 技艺<br> 科技本质<br> 动作：标准<br> 类型：攻击技<br> 射程：135米<br> 能量：14<br> A+4000<br> 眼中不再有敌人的实体，取而代之的是在其周围浮现的、由无数闪烁的0和1构成的脆弱数据轮廓。无需枪械，仅是目光一凝，一次无声的“咆哮”便已完成。<br> 被攻击命中的敌方单位视觉系统会被无穷无尽的破碎代码覆盖，如同亿万台故障的电视屏幕在眼前同时炸裂，听觉被尖锐的白噪音、无数种语言的碎片化尖叫、完全无规律的二进制嘶吼所淹没；思维进程被强行塞入了数以TB计的无关信息，对方的大脑或CPU的每一个线程都会被这些无法处理且无法丢弃的数据垃圾彻底塞满，导致大脑彻底死机，无法处理周围的其他数据，且对外界的一切刺激失去反应，彻底沉浸在自己颅内爆发的信息地狱之中，直到系统强制重启或进行垃圾清理为止。<br> 选定一名单位进行一次攻击，本次攻击伤害类型为物理-钝击伤害，如果目标为结构值，则伤害类型更改为穿刺伤害，画风上，是由过量的数据垃圾短时间涌入，对人脑照常物理性冲击，使得结构体处理器短时间无法同时处理，导致的结构体内部机械元器件损毁<br> 本次攻击视为物理-钝击/穿刺伤害取优结算，攻击可以将感知属性加入检定当中，附带伤害等量A级信息来源的眩晕异常点数，强韧豁免，这些异常点数提升至四档</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const f=e(d,[["render",n]]);export{D as __pageData,f as default};
